"use strict";(self.webpackChunkrrbtc_wiki_docusaurus=self.webpackChunkrrbtc_wiki_docusaurus||[]).push([[6326],{8056(e){e.exports=JSON.parse('{"tag":{"label":"hardware-wallet","permalink":"/tags/hardware-wallet","allTagsPath":"/tags","count":8,"items":[{"id":"entities/coldcard","title":"ColdCard","description":"ColdCard is a hardware wallet for advanced users prioritizing security verification, air-gapped signing, and open-source principles. Manufactured by Coinkite, widely used in multisig setups.","permalink":"/entities/coldcard"},{"id":"concepts/custody-models","title":"Custody Models","description":"The spectrum of bitcoin custody ranges from full self-custody to fully custodial exchange wallets. The right model depends on technical ability, threat model, and need for inheritance or recovery.","permalink":"/concepts/custody-models"},{"id":"entities/hwi","title":"HWI (Hardware Wallet Interface)","description":"Command-line tool and Python library for connecting hardware wallets to Bitcoin Core. Enables direct signing with devices like Trezor, Ledger, and Coldcard without trusting intermediary software.","permalink":"/entities/hwi"},{"id":"entities/ledger","title":"Ledger","description":"Ledger is a hardware wallet manufacturer using secure element (SE) chips to protect private keys. One of the most widely sold hardware wallets globally.","permalink":"/entities/ledger"},{"id":"concepts/multisig","title":"Multisig","description":"Multisignature (multisig) scripts set a condition where N public keys are recorded and at least M must provide signatures to unlock funds. This is expressed as an M-of-N threshold (e.g., 2-of-3).","permalink":"/concepts/multisig"},{"id":"entities/seedsigner","title":"SeedSigner","description":"Open-source, DIY Bitcoin signing device built from commodity hardware. Designed for air-gapped seed generation, transaction signing, and multisig coordination without trusting proprietary hardware.","permalink":"/entities/seedsigner"},{"id":"entities/trezor","title":"Trezor","description":"Trezor is a hardware wallet developed by SatoshiLabs. The first commercial hardware wallet (2014), known for fully open-source firmware.","permalink":"/entities/trezor"},{"id":"queries/which-custody-model-fits-my-threat-model","title":"Which Custody Model Fits My Threat Model?","description":"There is no universal \\"best\\" way to hold bitcoin. The right custody model depends on your technical ability, value at stake, threat model, and need for recovery or inheritance. This page walks through the decision process.","permalink":"/queries/which-custody-model-fits-my-threat-model"}],"unlisted":false}}')}}]);